fix.code:
package requirements {
    requirement def Shape {
        doc /* The system shall be a perfect cube of 1m^2. */
    }

    requirement def Material {
        doc /* The system shall be made of 2024 Aluminium. */
    }

    requirement def Weight {
        doc /* The system shall weigh no more than 1kg. */
    }

    requirement def ConflictResolution {
        doc /* If Shape, Material, and Weight cannot be simultaneously satisfied, Weight shall take precedence, Material shall be the next preference, and Shape shall be relaxed first. Resolution rationale: the 1 kg maximum mass is treated as the governing stakeholder constraint for handling and verification; 2024 Aluminium is preferred unless needed to meet mass; geometry is lowest priority and shall be updated through trade study when conflict remains. */
    }

    requirement massPriority : ConflictResolution {
        doc /* Governing priority requirement for the identified latent conflict. */
        refines Weight;
        refines Material;
        refines Shape;
    }
}

